previewCss:
.darma-loader-darma-custom-289 {
  width: fit-content;
  font-size: 34px;
  font-family: system-ui,sans-serif;
  font-weight: bold;
  text-transform: uppercase;
  color: #0000;
  -webkit-text-stroke: 1px var(--loader-color, #ca8a04);
  background: 
    linear-gradient(90deg,#0000 33%,var(--loader-color, #ca8a04) 0 67%,#0000 0) 
    0/300% 100% no-repeat text;
  animation: darma-loader-darma-custom-289-l2 2s linear infinite;
}
.darma-loader-darma-custom-289:before {
  content: "Loading";
}
@keyframes darma-loader-darma-custom-289-l2 {
  0%{background-position: 100%}
}

